```class Solution {
public:
    string countOfAtoms(string formula) {
        unordered_map<string, int> count;
        stack<unordered_map<string, int>> stack;
        stack.push(count);
        int i = 0, n = formula.size();
        while (i < n) {
            if (formula[i] == '(') {
                stack.push(unordered_map<string, int>());
                i++;
            } else if (formula[i] == ')') {
                unordered_map<string, int> top = stack.top();
                stack.pop();
                int num = 0, j = i + 1;
                while (j < n && isdigit(formula[j])) {
                    num = num * 10 + formula[j++] - '0';
                }
                if (!num) num = 1;
                for (auto& p : top) {
                    p.second *= num;
                    stack.top()[p.first] += p.second;
                }
                i = j;
            } else {
                string name;
                while (i < n && isupper(formula[i])) {
                    name += formula[i++];
                }
                while (i < n && islower(formula[i])) {
                    name += formula[i++];
                }
                int num = 0;
                while (i < n && isdigit(formula[i])) {
                    num = num * 10 + formula[i++] - '0';
                }
                if (!num) num = 1;
                stack.top()[name] += num;
            }
        }
        string res;
        for (auto& p : stack.top()) {
            res += p.first;
            if (p.second > 1) res += to_string(p.second);
        }
        sort(res.begin(), res.end());
        return res;
    }
};
